  h += '<button class="hm-btn" style="background:rgba(255,255,255,.12);color:#fff" data-action="redo-builder">'+_t('↪ Làm lại', '↪ Redo')+' ('+(undoInfo.canRedo ? (undoInfo.depth - undoInfo.position - 1) : 0)+')</button>';
