    css += '.mb-r5-code{margin:0;padding:12px;border-radius:16px;background:#0f172a;color:#e2e8f0;font-size:12px;line-height:1.55;white-space:pre-wrap;word-break:break-word;max-height:280px;overflow:auto}';
